// Building description types — OWNED by Dev A
// Output of the Gemini Vision agent. Rich enough that the renderer is just
// an instancer: it converts these declarative facts into Three.js meshes
// without making any architectural decisions of its own. The AI is the
// architect; the code only matérialises.

export type FacadeOrientation = 'north' | 'south' | 'east' | 'west';
export type RoofType = 'gable' | 'hip' | 'flat' | 'mansard' | 'shed';
export type RidgeAxis = 'x' | 'z';
export type FacadeMaterial = 'render' | 'brick' | 'wood' | 'stone';
export type OpeningType = 'window' | 'door' | 'garage_door';
export type WindowStyle = 'rectangular' | 'square' | 'arched' | 'french-window';
export type RoofFeatureType = 'chimney' | 'dormer' | 'skylight';
export type Visibility = 'clear' | 'partial' | 'obscured';
export type VolumeRole = 'main' | 'garage' | 'extension';

export interface Opening {
  type: OpeningType;
  /** Floor index, 0 = ground floor. */
  storey: number;
  /** 0 = left edge of facade, 1 = right edge. */
  horizontalPosition: number;
  width: number;
  height: number;
  style: WindowStyle;
  hasShutters: boolean;
}

export interface Facade {
  orientation: FacadeOrientation;
  visibility: Visibility;
  openings: Opening[];
}

export interface RoofFeature {
  type: RoofFeatureType;
  /** X position (east-west) in meters relative to the volume's center. */
  positionX: number;
  /** Z position (north-south) in meters relative to the volume's center. */
  positionZ: number;
  width: number;
  heightAboveRoof: number;
  depth: number;
}

export interface Roof {
  type: RoofType;
  /** Roof pitch in degrees. 0 for flat. */
  pitchDeg: number;
  /** x = east-west ridge, z = north-south ridge. */
  ridgeAxis: RidgeAxis;
  color: string;
  /** Eaves overhang in meters. */
  overhangM: number;
  features: RoofFeature[];
}

export interface Volume {
  role: VolumeRole;
  /** Volume center X (east-west). Relative to main building origin. */
---schema---
// Zod schema for Gemini structured output — OWNED by Dev A
// Mirrors buildingTypes.ts. Field-level descriptions become part of the
// prompt, so write them as if speaking to the AI.

import { z } from 'zod';

const hexColor = z.string().regex(/^#[0-9a-fA-F]{6}$/);

const openingSchema = z.object({
  type: z
    .enum(['window', 'door', 'garage_door'])
    .describe('window, door (front entry), or garage_door'),
  storey: z
    .number()
    .int()
    .min(0)
    .max(4)
    .describe('Floor index, 0 = ground floor'),
  horizontalPosition: z
    .number()
    .min(0)
    .max(1)
    .describe('Horizontal position on the facade. 0 = left edge, 0.5 = center, 1 = right edge.'),
  width: z.number().min(0.4).max(4).describe('Width in meters'),
  height: z.number().min(0.4).max(3).describe('Height in meters'),
  style: z
    .enum(['rectangular', 'square', 'arched', 'french-window'])
    .describe('Predominant opening style'),
  hasShutters: z
    .boolean()
    .describe('True if visible window shutters/persiennes are present'),
});

const facadeSchema = z.object({
  orientation: z.enum(['north', 'south', 'east', 'west']),
  visibility: z
    .enum(['clear', 'partial', 'obscured'])
    .describe('How well you can see this facade in the photos. obscured = not visible, hypothesize symmetric layout from visible facades.'),
  openings: z
    .array(openingSchema)

